VALUES
  ('aboriginal-f0899a01-moex-00147', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政程序法規定，關於聽證程序之進行，下列何者錯誤？', '["聽證應由行政機關首長親自主持，必要時得指定其他熟諳法令之人員在場協助之", "行政機關得依職權或當事人之申請，變更聽證期日或場所，但以有正當理由為限", "行政機關為使聽證順利進行，認有議定聽證程序進行之必要時，得於聽證期日前，舉行預備聽證", "聽證，除法律另有規定外，應公開以言詞為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00148', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依政府資訊公開法規定，下列何者係政府應主動公開之資訊？', '["司法院委託大學教授研究某司法制度興革之報告", "考選部所屬公務員作成之評估多元考試取才方式之報告", "行政院訴願審議委員會之會議紀錄", "金融監督管理委員會之會議紀錄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00149', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於相對人於行政程序中陳述意見之敘述，下列何者正確？', '["不於行政機關訂定之期間內提出陳述書者，得於事後隨時補提", "相對人依規定提出之陳述書，應為事實上及法律上陳述", "利害關係人提出陳述書為補充陳述時，無須釋明其利害關係之所在", "以言詞陳述意見者，行政機關無須作成紀錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00150', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願之敘述，下列何者錯誤？', '["訴願之提起，應自行政處分達到之次日起30日內為之", "利害關係人自行政處分公告期滿後，已逾3年者，不得提起訴願", "受理訴願機關得依職權命文書持有人提出文書，並得留置之", "受理訴願機關應通知訴願人、參加人或利害關係人到達指定處所陳述意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00151', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願管轄與原行政處分機關認定之敘述，下列何者錯誤？', '["有隸屬關係之下級機關依法辦理上級機關委任事件所為之行政處分，為受委任機關之行政處分", "上級機關本於法定職權所為之行政處分，交由下級機關執行者，以該下級機關為原行政處分機關", "對於二以上不同隸屬或不同層級之機關共為之行政處分，應向其共同之上級機關提起訴願", "無隸屬關係之機關辦理受託事件所為之行政處分，視為委託機關之行政處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00152', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願審議程序，下列敘述何者正確？', '["訴願人申請閱覽相關文件資料遭拒時，不得獨立提起訴訟", "受理訴願機關為釐清案件事實，原則上應舉行言詞辯論", "相關機關得因特定案件派員擔任訴願審議委員會委員", "訴願輔佐人得單獨向受理訴願機關申請閱覽卷宗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00153', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲之房屋被主管機關認定為違章建築，並已在迅速執行過程中被拆除完畢。甲若欲進一步尋求救濟時， 可以提起下列何種訴訟？', '["對於建築主管機關認定違章建築之處分，提起撤銷訴訟", "對於建築主管機關認定違章建築之處分，提起確認違法訴訟", "對於建築主管機關提起課予義務訴訟", "對於建築主管機關提起公益訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00154', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依確認訴訟之補充性原則，下列何者不受此一原則之限制？', '["確認行政處分違法之訴訟", "確認行政處分無效之訴訟", "確認公法上法律關係成立之訴訟", "確認公法上法律關係不成立之訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00155', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政訴訟法規定之訴訟費用，下列敘述何者錯誤？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣2千元", "對於確定之裁定聲請再審者，徵收裁判費新臺幣2千元", "適用通常訴訟程序之事件，徵收裁判費新臺幣4千元", "訴訟費用指裁判費及其他進行訴訟之必要費用，原則上由敗訴之當事人負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00156', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政訴訟之反訴，下列敘述何者錯誤？', '["對於撤銷訴訟，不得提起反訴", "被告意圖延滯訴訟而提起反訴者，行政法院得駁回之", "被告於言詞辯論終結前，得在本訴繫屬之行政法院提起反訴", "對於一般給付訴訟，不得提起反訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
